const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 3000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const code = error.status || error.code || 500;
    const message = error.message?.toLowerCase() || "";

    // Log for debugging
    console.error(`Gemini API Error [${code}]:`, error);

    const isRetryable = 
      code === 429 || 
      code === 500 || 
      code === 503 || 
      code === 504 ||
      message.includes('quota') || 
      message.includes('internal error') ||
      message.includes('server error') ||
      message.includes('deadline');

    if (retries > 0 && isRetryable) {
      const nextDelay = code === 429 ? delay * 5 : delay * 2;
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    // Increased text limit to ~2M characters to accommodate large books
    // Gemini 1.5 Pro/Flash has a >1M token context window, so 2M chars (~500k tokens) is safe
    const LIMIT = 2000000;
    const content = file.content.length > LIMIT ? file.content.substring(0, LIMIT) + "\n...[Content Truncated due to API Safety Limit]..." : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    // Using Pro for better reliability with complex JSON schemas and large context
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Examine the provided content and identify its title, author, and structure." }
        ]
      },
      config: {
        systemInstruction: "You are a professional book analyzer. Analyze the provided book content. Extract the title, author, and a list of major chapters (max 20). For each chapter, provide a brief title and a concise one-sentence description. Output strictly in valid JSON format matching the schema provided. Do not include markdown formatting or introductory text.",
        responseMimeType: "application/json",
        // Letting the model manage thinking tokens automatically for improved stability
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
